mapper.select:
SELECT * FROM ( SELECT * FROM ( SELECT COUNT(*) OVER() AS totalRow ,ROW_NUMBER(*) OVER(ORDER BY AA.payDt desc) AS currRow ,20 AS pageRowSize ,AA.* FROM ( SELECT pi.pay_dt AS payDt , pi.bill_acc_no AS billAccNo , ci.cust_nm AS custNm , pi.cust_pay_dt AS custPayDt , pi.pay_meth_cd AS payMethCd , pi.pay_amt AS payAmt , pi.rsn_cd AS rsnCd FROM pay_info pi , bill_acc_info bai , cust_info ci WHERE pi.pay_cd = 'BCK' AND pi.pay_dt >= #{fromDt} AND pi.pay_dt <= #{toDt} AND pi.bill_acc_no = bai.bill_acc_no AND bai.bill_acc_cust_no = ci.cust_no
bai.cmpn_cd = #{cmpnBizInfo.cmpnCd} AND bai.biz_cd = #{cmpnBizInfo.bizCd}
ORDER BY pi.pay_dt DESC ) AA ) pagingtable WHERE currRow <= #{endRow} ) WHERE currRow >= #{startRow}

SELECT * FROM ( SELECT * FROM ( SELECT COUNT(*) OVER() AS totalRow ,ROW_NUMBER(*) OVER(ORDER BY AA.ccardCanDate desc) AS currRow ,20 AS pageRowSize ,AA.* FROM ( SELECT tri.bill_acc_no AS billAccNo , ci.cust_nm AS custNm , tri.tns_cmpn_cd AS ccardCmpnCd , tri.pay_media_no AS ccardNo , tri.ccard_apv_no AS ccardApvNo , pi.cust_pay_dt AS ccardApvDate , tri.tns_rqt_dt AS ccardCanDate , tri.tns_rqt_amt AS canAmt , tri.amdr_id AS trtId , tri.amd_dt AS trtDt FROM tns_rqt_info tri , bill_acc_info bai , cust_info ci , pay_info pi WHERE tri.tns_rqt_div_cd = 'BIC' AND tri.tns_rqt_dt >= #{fromDt} AND tri.tns_rqt_dt <= #{toDt}
AND tri.tns_cmpn_cd = #{divCd}
bai.cmpn_cd = #{cmpnBizInfo.cmpnCd} AND bai.biz_cd = #{cmpnBizInfo.bizCd}
AND tri.bill_acc_no = bai.bill_acc_no AND bai.bill_acc_cust_no = ci.cust_no AND pi.bill_acc_no = tri.bill_acc_no AND pi.tns_rqt_seq = tri.tns_rqt_seq ORDER BY tri.tns_rqt_dt DESC ) AA ) pagingtable WHERE currRow <= #{endRow} ) WHERE currRow >= #{startRow}
